<?php
declare(strict_types=1);require_once __DIR__.'/_layout.php';$pdo=obtenerConexion();docenteCabecera('Inicio docente','inicio','Resumen académico basado únicamente en asignaciones reales.');$docenteId=(int)$GLOBALS['docentePortalId'];docenteSelectorSupervision($pdo);$cursos=cursosDocenteAtenea($pdo,$docenteId);$metricas=['cursos'=>count($cursos),'estudiantes'=>0,'contenidos'=>0,'pendientes'=>0];$recientes=[];$proximas=[];
if($docenteId){$q=$pdo->prepare("SELECT COUNT(DISTINCT estudiante_id) FROM estudiantes_docentes WHERE docente_id=:d AND estado='activo'");$q->execute(['d'=>$docenteId]);$metricas['estudiantes']=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT COUNT(*) FROM contenidos WHERE docente_id=:d');$q->execute(['d'=>$docenteId]);$metricas['contenidos']=(int)$q->fetchColumn();$q=$pdo->prepare("SELECT COUNT(*) FROM ev_entregadas ee JOIN evaluaciones e ON e.id=ee.evaluacion_id WHERE e.docente_id=:d AND ee.estado IN('pendiente','tardia')");$q->execute(['d'=>$docenteId]);$metricas['pendientes']=(int)$q->fetchColumn();$q=$pdo->prepare('SELECT c.titulo,c.estado,c.created_at,a.nombre asignatura FROM contenidos c JOIN asignaturas a ON a.id=c.asignatura_id WHERE c.docente_id=:d ORDER BY c.created_at DESC LIMIT 5');$q->execute(['d'=>$docenteId]);$recientes=$q->fetchAll();$q=$pdo->prepare("SELECT e.id,e.titulo,e.fecha_cierre,a.nombre asignatura FROM evaluaciones e JOIN asignaturas a ON a.id=e.asignatura_id WHERE e.docente_id=:d AND e.estado='publicada' AND e.fecha_cierre>=NOW() ORDER BY e.fecha_cierre LIMIT 5");$q->execute(['d'=>$docenteId]);$proximas=$q->fetchAll();}
?>
<?php if(!$docenteId):?><div class="card card-rounded"><div class="card-body text-center py-5"><i class="mdi mdi-account-search-outline display-4 text-primary"></i><h2 class="h5 mt-3">Selecciona un docente</h2><p class="text-muted mb-0">La supervisión no muestra información hasta elegir una cuenta docente activa.</p></div></div><?php else:?><div class="row g-3 mb-4"><?php foreach([['Cursos asignados',$metricas['cursos'],'mdi-book-open-page-variant'],['Estudiantes',$metricas['estudiantes'],'mdi-account-multiple'],['Contenidos',$metricas['contenidos'],'mdi-file-document'],['Entregas por revisar',$metricas['pendientes'],'mdi-clipboard-alert-outline']] as$m):?><div class="col-sm-6 col-lg-3"><div class="card card-rounded"><div class="card-body"><div class="d-flex align-items-center"><i class="mdi <?=$m[2]?> fs-1 text-primary me-3"></i><div><p class="statistics-title mb-1"><?=$m[0]?></p><h3 class="rate-percentage mb-0"><?=$m[1]?></h3></div></div></div></div></div><?php endforeach;?></div><?php if(!$cursos):?><div class="card card-rounded"><div class="card-body text-center py-5"><i class="mdi mdi-book-off-outline display-4 text-primary"></i><h2 class="h5 mt-3">Sin cursos asignados</h2><p class="text-muted mb-0">El administrador todavía no ha asignado cursos a este docente.</p></div></div><?php else:?><div class="row"><div class="col-lg-7 grid-margin stretch-card"><div class="card card-rounded"><div class="card-body"><h2 class="h5">Cursos asignados</h2><?php foreach($cursos as$c):?><div class="border-bottom py-3 d-flex justify-content-between"><div><strong><?=atenea_e($c['nombre'])?></strong><small class="d-block text-muted"><?=atenea_e($c['codigo'])?> · <?=$c['estudiantes']?> estudiantes</small></div><a class="btn btn-sm btn-outline-primary" href="<?=docenteUrl('curso.php',['id'=>$c['id']])?>">Ver curso</a></div><?php endforeach;?></div></div></div><div class="col-lg-5 grid-margin stretch-card"><div class="card card-rounded"><div class="card-body"><h2 class="h5">Próximas actividades</h2><?php foreach($proximas as$e):?><p><strong><?=atenea_e($e['titulo'])?></strong><small class="d-block"><?=atenea_e($e['asignatura'])?> · <?=date('d/m/Y H:i',strtotime($e['fecha_cierre']))?></small></p><?php endforeach;?><?php if(!$proximas):?><p class="text-muted">No hay actividades próximas publicadas.</p><?php endif;?></div></div></div></div><?php endif;?><?php endif;?><?php docentePie();
